class Solution {
public:
	int bfl(int n, int target) {
		int flips = 0;
		while (n != target) {
			// Use bitwise XOR to find the difference between n and target
			diff = n ^ target;
			// Count the number of 1s in the difference
			flips += __builtin_popcount(diff);
			// Move to the next bit
			n = n >> 1;
			if (n == 0) break;
		}
		return flips;
	}
}

int main() {
	int n, target;
	scanf("%d", &n);
	scanf("%d", &target);
	Solution s;
	int p = s.bfl(n, target);
	printf("%d", p);
	return 0;
}
